#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template <typename T> inline void rd(T &x)
{
	x=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')x=x*10+(ch^48),ch=getchar();
	flag ? x = -x : 0 ;
}
inline int max(int x,int y){return x>y?x:y;}
const int N=1e5+10,INF=0x3f3f3f3f;int n,m,a[N];
struct Matrix
{
	int a[2][2];inline Matrix(){memset(a,-0x3f,sizeof(a));}
	inline Matrix operator * (const Matrix &q)const
	{
		Matrix res;
		res.a[0][0]=max(a[0][0]+q.a[0][0],a[0][1]+q.a[1][0]);
		res.a[0][1]=max(a[0][0]+q.a[0][1],a[0][1]+q.a[1][1]);
		res.a[1][0]=max(a[1][0]+q.a[0][0],a[1][1]+q.a[1][0]);
		res.a[1][1]=max(a[1][0]+q.a[0][1],a[1][1]+q.a[1][1]);
		return res;
	}
	inline void debug(){printf("%d %d\n%d %d\n",a[0][0],a[0][1],a[1][0],a[1][1]);puts("-------");}
}mat[N],sm[N<<2];
int head[N],des[N<<1],nxt[N<<1],cgt;inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}


int dp[N][2],g[N][2],siz[N],mxs[N],loc[N],L[N],tot,til[N],fa[N],top[N];
inline void dfs1(int u=1,int f=0)
{
	siz[u]=1;fa[u]=f;int mx=0;grep(u,i)if(des[i]^f)
	{
		int v=des[i];dfs1(v,u);siz[u]+=siz[v];
		siz[v]>mx?mx=siz[mxs[u]=v]:0;
	}
}
inline void dfs2(int u=1,int fa=0,int tp=1)
{
	++tot;til[top[loc[L[u]=tot]=u]=tp]=tot;
	dp[u][0]=0;dp[u][1]=mat[u].a[1][0]=a[u];mat[u].a[0][0]=mat[u].a[0][1]=0;
	if(mxs[u])
	{
		int v=mxs[u];dfs2(v,u,tp);
		dp[u][0]=max(dp[v][0],dp[v][1]);dp[u][1]+=dp[v][0];
	}
	grep(u,i)if(des[i]^fa&&des[i]^mxs[u])
	{
		int v=des[i];dfs2(v,u,v);
		dp[u][0]+=max(dp[v][0],dp[v][1]);dp[u][1]+=dp[v][0];
		mat[u].a[0][1]=mat[u].a[0][0]+=max(dp[v][0],dp[v][1]);
		mat[u].a[1][0]+=dp[v][0];
	}
}

inline void update(int cur){sm[cur]=sm[cur<<1]*sm[cur<<1|1];}
inline void build(int l=1,int r=n,int cur=1)
{
	if(l==r)return sm[cur]=mat[loc[l]],void();int mid=(l+r)>>1;
	build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);update(cur);
}
inline void fxd(int x,int l=1,int r=n,int cur=1)
{
	if(l==r){sm[cur]=mat[loc[l]];return;}int mid=(l+r)>>1;
	x<=mid?fxd(x,l,mid,cur<<1):fxd(x,mid+1,r,cur<<1|1);update(cur);
}
inline Matrix qry(int ql,int qr,int l=1,int r=n,int cur=1)
{
	if(ql<=l&&r<=qr)return sm[cur];int mid=(l+r)>>1;
	if(qr<=mid)return qry(ql,qr,l,mid,cur<<1);
	if(ql>mid)return qry(ql,qr,mid+1,r,cur<<1|1);
	return qry(ql,qr,l,mid,cur<<1)*qry(ql,qr,mid+1,r,cur<<1|1);
}

inline void add(int u,int w)
{
	mat[u].a[1][0]+=w-a[u];a[u]=w;
	Matrix inv,nxt;while(u)
	{
		inv=qry(L[top[u]],til[top[u]]);fxd(L[u]);nxt=qry(L[top[u]],til[top[u]]);
//		printf("QwQ :: %d %d\n",L[top[u]],til[top[u]]);
//		nxt.debug();inv.debug();
		u=fa[top[u]];mat[u].a[0][1]=mat[u].a[0][0]+=max(nxt.a[0][0],nxt.a[1][0])-max(inv.a[0][0],inv.a[1][0]);
		mat[u].a[1][0]+=nxt.a[0][0]-inv.a[0][0];
	}
}

int main()
{
	n=read();m=read();rep(1,n,i)rd(a[i]);
	rep(2,n,i){int x=read(),y=read();ins(x,y);ins(y,x);}
	dfs1();dfs2();build();
//	rep(1,n,i)mat[i].debug();
//	rep(1,n,i)printf("%d ",L[i]);puts("");
//	rep(1,n,i)printf("%d ",til[i]);puts("");
//	rep(1,n,i)printf("%d ",dp[i][0]);puts("");
//	rep(1,n,i)printf("%d ",dp[i][1]);puts("");
	while(m--)
	{
		int u=read(),w;rd(w);add(u,w);Matrix res=qry(L[1],til[1]);
		printf("%d\n",max(res.a[0][0],res.a[1][0]));
	}
}
